class Solution:
    def mySqrt(self, x: int) -> int:
        if x < 2: return x
        lo, hi, ans = 1, x, 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if mid <= x // mid:
                ans = mid; lo = mid + 1
            else: hi = mid - 1
        return ans

